1	/**
2	 * FAM-02 — sweep geometry builder.
3	 *
4	 * Produces a Three.js BufferGeometry by extruding a closed 2D profile
5	 * along a 2D path. The path's first segment defines the orientation
6	 * for the profile when ``profilePlane === 'normal_to_path_start'``; in
7	 * that mode, the profile sits perpendicular to the path so a
8	 * window-handle path with a circular profile yields a cylinder.
9	 *
10	 * For ``profilePlane === 'work_plane'``, the profile is interpreted
11	 * in the X/Z plane (work-plane = ground) and the path provides the
12	 * extrusion direction — useful when the path is itself in 3D.
13	 *
14	 * Pure function, no Three.js scene side effects. The geometry is
15	 * unit-mm; callers apply scene-scale at the mesh level.
16	 */
17	
18	import * as THREE from 'three';
19	import type { SketchLine, SweepGeometryNode } from './types';
20	
21	/** Convert chained sketch lines into an ordered vertex list. */
22	export function sketchLinesToPath(lines: SketchLine[]): { x: number; y: number }[] {
23	  if (lines.length === 0) return [];
24	  const out: { x: number; y: number }[] = [{ x: lines[0].startMm.xMm, y: lines[0].startMm.yMm }];
25	  for (const line of lines) {
26	    out.push({ x: line.endMm.xMm, y: line.endMm.yMm });
27	  }
28	  return out;
29	}
30	
31	/** Convert a closed polyline of sketch lines into a Three.Shape. */
32	export function sketchLinesToShape(lines: SketchLine[]): THREE.Shape {
33	  const pts = sketchLinesToPath(lines);
34	  if (pts.length < 3) {
35	    throw new Error('sweepGeometry: profile needs at least 3 vertices');
36	  }
37	  // Close the loop by ignoring a duplicate trailing vertex.
38	  const closed =
39	    pts.length > 1 && pts[0].x === pts[pts.length - 1].x && pts[0].y === pts[pts.length - 1].y;
40	  const usable = closed ? pts.slice(0, -1) : pts;
41	  const shape = new THREE.Shape();
42	  shape.moveTo(usable[0].x, usable[0].y);
43	  for (let i = 1; i < usable.length; i++) {
44	    shape.lineTo(usable[i].x, usable[i].y);
45	  }
46	  shape.closePath();
47	  return shape;
48	}
49	
50	/**
51	 * Build a Three.js BufferGeometry for a sweep node.
52	 *
53	 * Implementation notes:
54	 *   - For a single straight path segment we use ``ExtrudeGeometry``
55	 *     with a depth equal to the segment length, then orient the
56	 *     extrusion along the path tangent.
57	 *   - For a multi-segment path we build a ``CatmullRomCurve3`` and
58	 *     extrude along it (Three's ExtrudeGeometry supports an
59	 *     ``extrudePath`` option).
60	 *   - When ``profilePlane === 'work_plane'`` the profile is placed
61	 *     in the X/Y plane and the path provides the direction vector.
62	 */
63	export function meshFromSweep(node: SweepGeometryNode): THREE.BufferGeometry {
64	  const pathPts = sketchLinesToPath(node.pathLines);
65	  if (pathPts.length < 2) {
66	    throw new Error('sweepGeometry: path needs at least 2 vertices');
67	  }
68	  const shape = sketchLinesToShape(node.profile);
69	
70	  // Single straight segment fast path → simple extrude
71	  if (pathPts.length === 2) {
72	    const dx = pathPts[1].x - pathPts[0].x;
73	    const dy = pathPts[1].y - pathPts[0].y;
74	    const length = Math.hypot(dx, dy);
75	    if (length === 0) {
76	      throw new Error('sweepGeometry: zero-length path');
77	    }
78	    const geom = new THREE.ExtrudeGeometry(shape, {
79	      depth: length,
80	      bevelEnabled: false,
81	      steps: 1,
82	    });
83	    // ExtrudeGeometry extrudes along +Z. Rotate so the extrusion
84	    // aligns with the 2D path direction in the X/Y plane.
85	    const angle = Math.atan2(dy, dx);
86	    if (node.profilePlane === 'normal_to_path_start') {
87	      // Profile is perpendicular to the path. Map +Z (extrusion axis)
88	      // to the path direction in the X/Y plane.
89	      geom.rotateY(Math.PI / 2);
90	      geom.rotateZ(angle);
91	    } else {
92	      // Profile lives in the work plane; +Z extrusion is "up".
93	      // Translate the start to (pathPts[0].x, pathPts[0].y, 0).
94	    }
95	    geom.translate(pathPts[0].x, pathPts[0].y, 0);
96	    return geom;
97	  }
98	
99	  // Multi-segment path → curve-driven extrusion.
100	  const curve = new THREE.CatmullRomCurve3(
101	    pathPts.map((p) => new THREE.Vector3(p.x, p.y, 0)),
102	    false,
103	    'catmullrom',
104	    0.0,
105	  );
106	  const geom = new THREE.ExtrudeGeometry(shape, {
107	    extrudePath: curve,
108	    bevelEnabled: false,
109	    steps: Math.max(2, pathPts.length * 8),
110	  });
111	  return geom;
112	}
113	
114	/** Bounding-box helper that's stable across Three.js versions. */
115	export function sweepBoundingBox(node: SweepGeometryNode): {
116	  min: { x: number; y: number; z: number };
117	  max: { x: number; y: number; z: number };
118	} {
119	  const geom = meshFromSweep(node);
120	  geom.computeBoundingBox();
121	  const bb = geom.boundingBox!;
122	  const result = {
123	    min: { x: bb.min.x, y: bb.min.y, z: bb.min.z },
124	    max: { x: bb.max.x, y: bb.max.y, z: bb.max.z },
125	  };
126	  geom.dispose();
127	  return result;
128	}
129

