1	import * as THREE from 'three';
2	import type { Element } from '@bim-ai/core';
3	import type { ViewportPaintBundle } from '../../viewport/materials';
4	import { resolveParam, type FamilyDefinition } from '../types';
5	import { resolveWindowOutline, resolveWindowOutlineKind } from './windowOutline';
6	
7	export type WindowGeomInput = {
8	  win: Extract<Element, { kind: 'window' }>;
9	  wall: Extract<Element, { kind: 'wall' }>;
10	  elevM: number;
11	  paint: ViewportPaintBundle | null;
12	  familyDef: FamilyDefinition | undefined;
13	  /** Required for `outlineKind: 'gable_trapezoid'` to look up `attachedRoofId`. */
14	  elementsById?: Record<string, Element>;
15	};
16	
17	const FALLBACK_COLOR = '#cbd5e1';
18	const FALLBACK_GLAZING = '#c8d8ea';
19	
20	function readGlazingColor(): string {
21	  if (typeof document === 'undefined') return FALLBACK_GLAZING;
22	  try {
23	    const v = getComputedStyle(document.documentElement).getPropertyValue('--cat-glazing').trim();
24	    return v || FALLBACK_GLAZING;
25	  } catch {
26	    return FALLBACK_GLAZING;
27	  }
28	}
29	
30	function addEdges(mesh: THREE.Mesh): void {
31	  const edges = new THREE.EdgesGeometry(mesh.geometry, 15);
32	  const lines = new THREE.LineSegments(
33	    edges,
34	    new THREE.LineBasicMaterial({ color: '#1a1a1a', linewidth: 1 }),
35	  );
36	  lines.renderOrder = 1;
37	  mesh.add(lines);
38	}
39	
40	export function buildWindowGeometry(input: WindowGeomInput): THREE.Group {
41	  const { win, wall, paint, familyDef, elementsById } = input;
42	
43	  const ip = win.overrideParams;
44	  const typeEntry = win.familyTypeId
45	    ? familyDef?.defaultTypes.find((t) => t.id === win.familyTypeId)
46	    : undefined;
47	  const tp = typeEntry?.parameters;
48	
49	  // Resolve sillMm first so it can inform heightMm clamp
50	  const rawSillMm = Number(resolveParam('sillMm', ip, tp, familyDef, win.sillHeightMm));
51	  const sillMm = THREE.MathUtils.clamp(rawSillMm, 60, wall.heightMm - 80);
52	
53	  const rawWidthMm = Number(resolveParam('widthMm', ip, tp, familyDef, win.widthMm));
54	  const rawHeightMm = Number(resolveParam('heightMm', ip, tp, familyDef, win.heightMm));
55	  const rawDepthMm = Number(resolveParam('frameDepthMm', ip, tp, familyDef, wall.thicknessMm + 20));
56	  const frameSectMm = Number(resolveParam('frameSectMm', ip, tp, familyDef, 60));
57	  const glazingAlpha = Number(resolveParam('glazingAlpha', ip, tp, familyDef, 0.35));
58	
59	  const outerW = THREE.MathUtils.clamp(rawWidthMm / 1000, 0.14, 4.0);
60	  const outerH = THREE.MathUtils.clamp(
61	    rawHeightMm / 1000,
62	    0.05,
63	    (wall.heightMm - sillMm - 60) / 1000,
64	  );
65	  const depth = THREE.MathUtils.clamp(rawDepthMm / 1000, 0.06, 0.5);
66	  const frameSect = frameSectMm / 1000;
67	
68	  const frameColor = paint?.categories.window.color ?? FALLBACK_COLOR;
69	  const frameMat = new THREE.MeshStandardMaterial({
70	    color: frameColor,
71	    roughness: paint?.categories.window.roughness ?? 0.6,
72	    metalness: paint?.categories.window.metalness ?? 0.05,
73	  });
74	
75	  const group = new THREE.Group();
76	  group.userData.bimPickId = win.id;
77	
78	  const glazingMat = new THREE.MeshStandardMaterial({
79	    color: readGlazingColor(),
80	    roughness: 0.05,
81	    metalness: 0.0,
82	    opacity: glazingAlpha,
83	    transparent: true,
84	    side: THREE.DoubleSide,
85	    envMapIntensity: 1.2,
86	  });
87	
88	  const outlineKind = resolveWindowOutlineKind(win);
89	  const outlinePoly =
90	    outlineKind === 'rectangle'
91	      ? null
92	      : elementsById
93	        ? resolveWindowOutline(win, wall, elementsById)
94	        : null;
95	
96	  if (outlinePoly && outlinePoly.length >= 3) {
97	    // KRN-12: variable-shape outline. Glass pane = polygon-shaped extruded
98	    // sliver (a thin extrusion through wall thickness gives the glass body).
99	    // Frame omitted for non-rectangular outlines until FAM-02 lands — sweep
100	    // along the polygon perimeter is a separate workpackage.
101	    // outline coords are in mm with origin at sill-centre; group origin sits
102	    // at sill-centre (caller positions accordingly).
103	    const shape = new THREE.Shape();
104	    shape.moveTo(outlinePoly[0].xMm / 1000, outlinePoly[0].yMm / 1000);
105	    for (let i = 1; i < outlinePoly.length; i++) {
106	      shape.lineTo(outlinePoly[i].xMm / 1000, outlinePoly[i].yMm / 1000);
107	    }
108	    shape.lineTo(outlinePoly[0].xMm / 1000, outlinePoly[0].yMm / 1000);
109	    const glassGeom = new THREE.ExtrudeGeometry(shape, {
110	      depth: 0.012,
111	      bevelEnabled: false,
112	    });
113	    glassGeom.translate(0, 0, -0.006);
114	    const glazing = new THREE.Mesh(glassGeom, glazingMat);
115	    glazing.castShadow = false;
116	    glazing.userData.bimPickId = win.id;
117	    group.add(glazing);
118	    return group;
119	  }
120	
121	  // Rectangular path — original frame + glass + optional mullion render.
122	  const glazingW = Math.max(outerW - 2 * frameSect, 0.01);
123	  const glazingH = Math.max(outerH - 2 * frameSect, 0.01);
124	
125	  const frameGroup = new THREE.Group();
126	
127	  function frameMesh(w: number, h: number, d: number, x: number, y: number): THREE.Mesh {
128	    const m = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), frameMat);
129	    m.position.set(x, y, 0);
130	    m.castShadow = m.receiveShadow = true;
131	    m.userData.bimPickId = win.id;
132	    addEdges(m);
133	    return m;
134	  }
135	
136	  // head
137	  frameGroup.add(frameMesh(outerW, frameSect, depth, 0, outerH / 2 - frameSect / 2));
138	  // sill
139	  frameGroup.add(frameMesh(outerW, frameSect, depth, 0, -(outerH / 2 - frameSect / 2)));
140	  // jamb-L
141	  frameGroup.add(frameMesh(frameSect, outerH, depth, -(outerW / 2 - frameSect / 2), 0));
142	  // jamb-R
143	  frameGroup.add(frameMesh(frameSect, outerH, depth, outerW / 2 - frameSect / 2, 0));
144	
145	  group.add(frameGroup);
146	
147	  const glazing = new THREE.Mesh(new THREE.BoxGeometry(glazingW, glazingH, 0.006), glazingMat);
148	  glazing.castShadow = false;
149	  glazing.userData.bimPickId = win.id;
150	  group.add(glazing);
151	
152	  if (outerW > 1.2) {
153	    const mullion = new THREE.Mesh(new THREE.BoxGeometry(frameSect, glazingH, 0.012), frameMat);
154	    mullion.castShadow = mullion.receiveShadow = true;
155	    mullion.userData.bimPickId = win.id;
156	    addEdges(mullion);
157	    group.add(mullion);
158	  }
159	
160	  return group;
161	}

